const items = $input.first().json.data ?? $input.all().map(i => i.json);
const item = Array.isArray(items) ? items[0] : items;
return [{ json: item }];

const scrapeResult = $input.first().json;
const product = $('Listing-Daten extrahieren').first().json;

const statusCode = scrapeResult.statusCode ?? scrapeResult.status ?? 200;
const html = typeof scrapeResult.body === 'string' ? scrapeResult.body : (scrapeResult.data ?? '');

let detectedStatus = 'active';
let priceCents = product.priceCents;
let priceRaw = null;
let changeReason = null;

// Gelöscht: HTTP-Fehler oder Redirect auf Homepage
if (statusCode >= 400 || statusCode === 0) {
  detectedStatus = 'deleted';
  changeReason = `HTTP ${statusCode} – Anzeige nicht mehr erreichbar`;
} else if (
  html.includes('nicht mehr verfügbar') ||
  html.includes('Anzeige wurde gelöscht') ||
  html.includes('existiert nicht mehr') ||
  html.includes('Ad not found') ||
  html.length < 500
) {
  detectedStatus = 'deleted';
  changeReason = 'Anzeige nicht mehr verfügbar (Seiteninhalt)';
} else {
  // Reserviert prüfen
  if (
    html.includes('>Reserviert<') ||
    html.includes('"Reserviert"') ||
    html.includes('badge-hint-reserved') ||
    html.includes('is--reserviert') ||
    html.includes('article--reserved') ||
    html.toLowerCase().includes('reserviert')
  ) {
    detectedStatus = 'reserved';
    changeReason = 'Anzeige als Reserviert markiert';
  }

  // Preis parsen – Kleinanzeigen nutzt itemprop="price"
  const priceMetaMatch = html.match(/itemprop=["']price["'][^>]*content=["']([^"']+)["']/) ||
                          html.match(/content=["']([^"']+)["'][^>]*itemprop=["']price["']/);
  if (priceMetaMatch) {
    const val = parseFloat(priceMetaMatch[1].replace(',', '.'));
    if (!isNaN(val) && val > 0) {
      const parsed = Math.round(val * 100);
      if (parsed !== product.priceCents) {
        changeReason = changeReason ?? `Preis geändert: ${product.priceCents} → ${parsed} Cent`;
        priceCents = parsed;
      }
    }
  }

  // Rohpreis-String für Logs
  const rawMatch = html.match(/class=["'][^"']*boxedarticle--price[^"']*["'][^>]*>([^<]{1,30})/) ||
                   html.match(/class=["'][^"']*price[^"']*["'][^>]*>\s*([\d.,\s€]{3,20})/);
  if (rawMatch) {
    priceRaw = rawMatch[1].trim();
  }
}

// Mapping detectedStatus → availabilityStatus
const statusMap = {
  active:   'in_stock',
  reserved: 'out_of_stock',
  deleted:  'discontinued',
};
const newAvailability = statusMap[detectedStatus];

// Änderung nötig?
const availabilityChanged = newAvailability !== product.availabilityStatus;
const priceChanged = priceCents !== product.priceCents && priceCents !== null;
const needsUpdate = availabilityChanged || priceChanged;

return [{
  json: {
    productId: product.id,
    productName: product.name,
    kleinanzeigenUrl: product.kleinanzeigenUrl,
    detectedStatus,
    currentAvailability: product.availabilityStatus,
    newAvailability,
    currentPriceCents: product.priceCents,
    newPriceCents: priceCents,
    priceRaw,
    needsUpdate,
    availabilityChanged,
    priceChanged,
    changeReason,
  }
}];

const d = $input.first().json;
const payload = {};

if (d.availabilityChanged) {
  payload.availability_status = d.newAvailability;
}

// Preis nur updaten wenn Variante vorhanden und Preis valide
if (d.priceChanged && d.newPriceCents > 0) {
  // Preis-Update erfolgt über separate Varianten-Logik
  // Hier nur als Notiz – Preis-Update via variants wäre ein eigener PATCH
  payload._priceNote = `Preis auf Kleinanzeigen: ${d.newPriceCents} Cent (war: ${d.currentPriceCents})`;
}

console.log(`[KA Monitor] Update für "${d.productName}" (${d.productId}):`, JSON.stringify(payload));
console.log(`Grund: ${d.changeReason}`);

return [{ json: { productId: d.productId, productName: d.productName, payload, changeReason: d.changeReason } }];

const d = $('Listing-Status parsen').first().json;
const result = $input.first().json;
console.log(`✓ [KA Monitor] "${d.productName}" aktualisiert: ${d.currentAvailability} → ${d.newAvailability}. Grund: ${d.changeReason}`);
return $input.all();

const d = $input.first().json;
console.log(`✓ [KA Monitor] "${d.productName}" unverändert (${d.currentAvailability})`);
return $input.all();
